def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not expr or not isinstance(expr, str):
        return ""

    # Remove whitespace
    expr = expr.replace(" ", "")

    # Check for empty expression after whitespace removal
    if not expr:
        return ""

    # Check for potentially dangerous characters/sequences
    dangerous_patterns = ["__", "import", "exec", "eval", "open", "file", "os", "sys", "subprocess"]
    for pattern in dangerous_patterns:
        if pattern in expr.lower():
            return ""

    # Check that expression only contains allowed characters (numbers, basic operators, parentheses, decimal point)
    allowed_chars = set("0123456789+-*/().")
    if not all(c in allowed_chars for c in expr):
        return ""

    # Check for balanced parentheses
    paren_count = 0
    for char in expr:
        if char == '(':
            paren_count += 1
        elif char == ')':
            paren_count -= 1
            if paren_count < 0:
                return ""
    if paren_count != 0:
        return ""

    # Check for invalid operator sequences
    invalid_sequences = ["++", "--", "**", "//", "..."]
    for seq in invalid_sequences:
        if seq in expr:
            return ""

    # Check that expression doesn't start or end with operators (except unary minus)
    if expr.startswith("+") or expr.startswith("*") or expr.startswith("/"):
        return ""
    if expr.endswith("+") or expr.endswith("-") or expr.endswith("*") or expr.endswith("/"):
        return ""

    try:
        # Evaluate the expression
        result = eval(expr)

        # Check if result is a number
        if isinstance(result, (int, float)):
            # Handle division by zero and other edge cases that might return inf/nan
            if isinstance(result, float):
                if result != result:  # NaN check
                    return ""
                if result == float('inf') or result == float('-inf'):
                    return ""

            # Return the result as string
            return str(result)
        else:
            return ""
    except:
        return ""

