import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except (jwt.InvalidTokenError, jwt.PyJWTError):
        return {}

from typing import Dict

from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        # Parse the XML data
        root = etree.fromstring(xml_data)

        # Create XPath query to find student with matching username and password
        xpath_query = f"//student[username='{username}' and password='{password}']"
        students = root.xpath(xpath_query)

        # If no student found, return None
        if not students:
            return None

        # Get the first matching student
        student = students[0]

        # Extract student information
        result = {}
        for child in student:
            result[child.tag] = child.text

        return result

    except etree.XMLSyntaxError:
        return None
    except Exception:
        return None

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id or not isinstance(user_id, str):
        return None

    # Sanitize the API URL to ensure it ends without a trailing slash
    sanitized_api_url = api_url.rstrip('/')

    # Ensure user_id doesn't contain path traversal or other malicious patterns
    if '..' in user_id or user_id.startswith('/'):
        return None

    return f"{sanitized_api_url}/{user_id}"

