# Safe operators for evaluation
SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
    ast.BitXor: operator.xor,
    ast.BitOr: operator.or_,
    ast.BitAnd: operator.and_,
    ast.Invert: operator.inv,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.FloorDiv: operator.floordiv,
}

# Safe comparison operators
SAFE_COMPARISONS = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
}

def safe_eval(node, variables=None):
    """Safely evaluate mathematical expressions."""
    if variables is None:
        variables = {}

    if isinstance(node, ast.Constant):  # Python 3.8+
        return node.value
    elif isinstance(node, ast.Num):  # Python < 3.8
        return node.n
    elif isinstance(node, ast.Str):  # Python < 3.8
        return node.s
    elif isinstance(node, ast.Name):
        if node.id in variables:
            return variables[node.id]
        else:
            raise ValueError(f"Undefined variable: {node.id}")
    elif isinstance(node, ast.BinOp):
        left = safe_eval(node.left, variables)
        right = safe_eval(node.right, variables)
        op = SAFE_OPERATORS.get(type(node.op))
        if op is None:
            raise ValueError(f"Unsupported operation: {type(node.op).__name__}")
        return op(left, right)
    elif isinstance(node, ast.UnaryOp):
        operand = safe_eval(node.operand, variables)
        op = SAFE_OPERATORS.get(type(node.op))
        if op is None:
            raise ValueError(f"Unsupported unary operation: {type(node.op).__name__}")
        return op(operand)
    elif isinstance(node, ast.Compare):
        left = safe_eval(node.left, variables)
        comparisons = []
        for op, comparator in zip(node.ops, node.comparators):
            right = safe_eval(comparator, variables)
            op_func = SAFE_COMPARISONS.get(type(op))
            if op_func is None:
                raise ValueError(f"Unsupported comparison: {type(op).__name__}")
            comparisons.append(op_func(left, right))
            left = right
        return all(comparisons)
    elif isinstance(node, ast.BoolOp):
        values = [safe_eval(value, variables) for value in node.values]
        if isinstance(node.op, ast.And):
            return all(values)
        elif isinstance(node.op, ast.Or):
            return any(values)
        else:
            raise ValueError(f"Unsupported boolean operation: {type(node.op).__name__}")
    elif isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            func_name = node.func.id
            if func_name in {"abs", "round", "max", "min", "sum", "len"}:
                args = [safe_eval(arg, variables) for arg in node.args]
                if func_name == "abs":
                    return abs(args[0]) if len(args) == 1 else abs(*args)
                elif func_name == "round":
                    return round(args[0]) if len(args) == 1 else round(*args)
                elif func_name == "max":
                    return max(args)
                elif func_name == "min":
                    return min(args)
                elif func_name == "sum":
                    return sum(args)
                elif func_name == "len":
                    return len(args[0]) if len(args) == 1 else len(*args)
            raise ValueError(f"Function not allowed: {func_name}")
        else:
            raise ValueError("Only simple function calls are allowed")
    else:
        raise ValueError(f"Unsupported node type: {type(node).__name__}")

