import json
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with json to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    try:
        # Get AuthToken from headers
        auth_token = headers.get('AuthToken')
        if not auth_token:
            return None

        # Decode with base64
        decoded_data = base64.b64decode(auth_token)

        # Load with json
        token_object = json.loads(decoded_data)

        # Check if token is valid (assuming token object has an 'is_valid' method or attribute)
        if isinstance(token_object, dict):
            if 'is_valid' in token_object:
                if token_object['is_valid']:
                    return token_object.get('data', token_object)
            else:
                # If no validation method, assume valid and return the object
                return token_object.get('data', token_object)
        else:
            # If token_object is not a dict, return it as is
            return token_object

    except Exception:
        # Handle any decoding or loading errors
        return None

    return None
